/**
 * wasm-substrate.test.ts -- Verify WASM acceleration + pure-TS fallback
 *
 * WASM init may fail in test environments (missing .wasm, no fetch, etc.)
 * and that is expected. The critical invariant: every function produces
 * correct results regardless of whether WASM loaded.
 */

import { describe, expect, test, beforeAll, afterAll } from 'vitest';
import {
  initWasmSubstrate,
  resetWasmSubstrate,
  substrateStatus,
  godWeight,
  buleyeanDistribution,
  buleNumber,
  shannonEntropy,
  fanoCollide,
  omegaSolve,
  godWeightBatch,
  buleyeanDistributionBatch,
  shannonEntropyBatch,
  buleNumberBatch,
  fanoCollideBatch,
  omegaSolveBatch,
} from './wasm-substrate';

// ─── Lifecycle ──────────────────────────────────────────────────────────────

describe('wasm-substrate', () => {
  beforeAll(async () => {
    // Attempt WASM init. If it fails, that is fine -- tests verify fallback.
    await initWasmSubstrate();
    const s = substrateStatus();
    // Log which path we are testing so CI output is clear
    console.log(
      `[wasm-substrate] buleyean=${s.buleyean}, fano=${s.fano}, attempted=${s.attempted}`
    );
  });

  afterAll(() => {
    resetWasmSubstrate();
  });

  // ─── 1. WASM init reports status ─────────────────────────────────────────

  test('substrateStatus reports attempted=true after init', () => {
    const s = substrateStatus();
    expect(s.attempted).toBe(true);
    // buleyean and fano may be true or false depending on env
    expect(typeof s.buleyean).toBe('boolean');
    expect(typeof s.fano).toBe('boolean');
  });

  // ─── 2. godWeight matches TS implementation ──────────────────────────────

  test('godWeight matches R - min(v, R) + 1 for sweep', () => {
    for (let R = 0; R <= 20; R++) {
      for (let v = 0; v <= 25; v++) {
        const expected = R - Math.min(v, R) + 1;
        expect(godWeight(R, v)).toBe(expected);
      }
    }
  });

  test('godWeight always >= 1 (the sliver)', () => {
    for (let R = 0; R < 50; R++) {
      for (let v = 0; v < 50; v++) {
        expect(godWeight(R, v)).toBeGreaterThanOrEqual(1);
      }
    }
  });

  // ─── 3. buleyeanDistribution sums to 1 ──────────────────────────────────

  test('buleyeanDistribution sums to 1', () => {
    const counts = [0, 1, 2, 3, 4];
    const round = 10;
    const dist = buleyeanDistribution(counts, round);
    expect(dist.length).toBe(counts.length);
    const sum = dist.reduce((a, b) => a + b, 0);
    expect(sum).toBeCloseTo(1.0, 10);
    // All entries positive
    for (const p of dist) {
      expect(p).toBeGreaterThan(0);
    }
  });

  test('buleyeanDistribution all entries positive', () => {
    const dist = buleyeanDistribution([5, 5, 5, 5], 10);
    for (const p of dist) {
      expect(p).toBeGreaterThan(0);
    }
  });

  // ─── 4. Bule of uniform = 0 ─────────────────────────────────────────────

  test('buleNumber of uniform counts is 0', () => {
    expect(buleNumber([3, 3, 3, 3])).toBe(0);
    expect(buleNumber([0, 0, 0])).toBe(0);
    expect(buleNumber([100, 100])).toBe(0);
  });

  test('buleNumber of non-uniform is positive', () => {
    expect(buleNumber([0, 1, 2, 3])).toBe(3);
    expect(buleNumber([10, 20])).toBe(10);
  });

  // ─── 5. shannonEntropy of uniform is log2(n) ────────────────────────────

  test('shannonEntropy of uniform distribution = log2(n)', () => {
    const n = 4;
    const uniform = new Array(n).fill(1 / n);
    const h = shannonEntropy(uniform);
    expect(h).toBeCloseTo(Math.log2(n), 8);
  });

  test('shannonEntropy of degenerate distribution = 0', () => {
    // All mass on one outcome
    const h = shannonEntropy([1, 0, 0, 0]);
    expect(h).toBeCloseTo(0, 10);
  });

  // ─── 6. fanoCollide is commutative ───────────────────────────────────────

  test('fanoCollide is commutative', () => {
    for (let a = 0; a < 8; a++) {
      for (let b = 0; b < 8; b++) {
        expect(fanoCollide(a, b)).toBe(fanoCollide(b, a));
      }
    }
  });

  test('fanoCollide with zero is identity', () => {
    for (let a = 0; a < 8; a++) {
      expect(fanoCollide(a, 0)).toBe(a);
    }
  });

  test('fanoCollide self-inverse (a ^ a = 0)', () => {
    for (let a = 0; a < 8; a++) {
      expect(fanoCollide(a, a)).toBe(0);
    }
  });

  // ─── 7. omegaSolve produces correct length ──────────────────────────────

  test('omegaSolve returns 9-byte result for 9-byte inputs', () => {
    const current = new Uint8Array([1, 2, 3, 4, 5, 6, 7, 0, 1]);
    const forces = new Uint8Array([0, 1, 1, 0, 2, 0, 3, 1, 0]);
    const result = omegaSolve(current, forces);
    expect(result.length).toBe(9);
    // Each byte is XOR of current and force
    for (let i = 0; i < 9; i++) {
      expect(result[i]).toBe(current[i]! ^ forces[i]!);
    }
  });

  // ─── 8. Batch godWeight matches single ───────────────────────────────────

  test('godWeightBatch matches single godWeight calls', () => {
    const rounds = [5, 10, 15, 20, 0];
    const rejections = [0, 3, 15, 25, 0];
    const batch = godWeightBatch(rounds, rejections);
    expect(batch.length).toBe(rounds.length);
    for (let i = 0; i < rounds.length; i++) {
      expect(batch[i]).toBe(godWeight(rounds[i]!, rejections[i]!));
    }
  });

  // ─── 9. Batch buleNumber matches single ──────────────────────────────────

  test('buleNumberBatch matches single buleNumber calls', () => {
    // 2 groups of 3 agents each
    const allCounts = [0, 1, 2, 5, 5, 5];
    const agentsPerGroup = 3;
    const groupCount = 2;
    const batch = buleNumberBatch(allCounts, agentsPerGroup, groupCount);
    expect(batch.length).toBe(groupCount);
    expect(batch[0]).toBe(buleNumber([0, 1, 2])); // 2
    expect(batch[1]).toBe(buleNumber([5, 5, 5])); // 0
  });

  // ─── 10. Batch entropy matches single ────────────────────────────────────

  test('shannonEntropyBatch matches single shannonEntropy calls', () => {
    // 2 groups of 3 entries each
    const dist = [0.5, 0.25, 0.25, 1 / 3, 1 / 3, 1 / 3];
    const batch = shannonEntropyBatch(dist, 3, 2);
    expect(batch.length).toBe(2);
    expect(batch[0]).toBeCloseTo(shannonEntropy([0.5, 0.25, 0.25]), 8);
    expect(batch[1]).toBeCloseTo(shannonEntropy([1 / 3, 1 / 3, 1 / 3]), 8);
  });

  // ─── 11. Batch omegaSolve matches single ─────────────────────────────────

  test('omegaSolveBatch matches single omegaSolve calls', () => {
    const c1 = new Uint8Array([1, 2, 3, 4, 5, 6, 7, 0, 1]);
    const f1 = new Uint8Array([0, 1, 1, 0, 2, 0, 3, 1, 0]);
    const c2 = new Uint8Array([7, 6, 5, 4, 3, 2, 1, 0, 0]);
    const f2 = new Uint8Array([1, 1, 1, 1, 1, 1, 1, 1, 1]);

    const current = new Uint8Array([...c1, ...c2]);
    const forces = new Uint8Array([...f1, ...f2]);

    const batchResult = omegaSolveBatch(current, forces, 2);
    const single1 = omegaSolve(c1, f1);
    const single2 = omegaSolve(c2, f2);

    expect(batchResult.length).toBe(18);
    for (let i = 0; i < 9; i++) {
      expect(batchResult[i]).toBe(single1[i]);
      expect(batchResult[9 + i]).toBe(single2[i]);
    }
  });

  // ─── 12. Batch fanoCollide matches single ────────────────────────────────

  test('fanoCollideBatch matches single fanoCollide calls', () => {
    const as = [0, 1, 2, 3, 4, 5, 6, 7];
    const bs = [7, 6, 5, 4, 3, 2, 1, 0];
    const batch = fanoCollideBatch(as, bs);
    expect(batch.length).toBe(as.length);
    for (let i = 0; i < as.length; i++) {
      expect(batch[i]).toBe(fanoCollide(as[i]!, bs[i]!));
    }
  });

  // ─── 13. Reset clears WASM state ─────────────────────────────────────────

  test('resetWasmSubstrate clears state', () => {
    resetWasmSubstrate();
    const s = substrateStatus();
    expect(s.attempted).toBe(false);
    expect(s.buleyean).toBe(false);
    expect(s.fano).toBe(false);
    // Functions still work (fallback)
    expect(godWeight(10, 3)).toBe(8);
    expect(buleNumber([1, 1, 1])).toBe(0);
  });

  // ─── 14. Fallback path produces correct results after reset ──────────────

  test('pure-TS fallback after reset produces identical results', () => {
    resetWasmSubstrate();
    // godWeight
    expect(godWeight(10, 0)).toBe(11);
    expect(godWeight(10, 10)).toBe(1);
    expect(godWeight(10, 15)).toBe(1);
    // distribution sums to 1
    const dist = buleyeanDistribution([0, 5, 10], 10);
    const sum = dist.reduce((a, b) => a + b, 0);
    expect(sum).toBeCloseTo(1.0, 10);
    // entropy
    expect(shannonEntropy([0.5, 0.5])).toBeCloseTo(1.0, 8);
    // fanoCollide
    expect(fanoCollide(3, 5)).toBe(3 ^ 5);
    // omegaSolve
    const r = omegaSolve(
      new Uint8Array([1, 0, 0, 0, 0, 0, 0, 0, 0]),
      new Uint8Array([0, 0, 0, 0, 0, 0, 0, 0, 0])
    );
    expect(r[0]).toBe(1);
  });

  // ─── 15. buleyeanDistribution batch matches single ───────────────────────

  test('buleyeanDistributionBatch groups match single calls', () => {
    resetWasmSubstrate();
    // 2 groups of 4 agents
    const allCounts = [0, 1, 2, 3, 4, 4, 4, 4];
    const batch = buleyeanDistributionBatch(allCounts, 4, 2);
    expect(batch.length).toBe(8);
    // Each group sums to 1
    const sum1 = batch.slice(0, 4).reduce((a, b) => a + b, 0);
    const sum2 = batch.slice(4, 8).reduce((a, b) => a + b, 0);
    expect(sum1).toBeCloseTo(1.0, 10);
    expect(sum2).toBeCloseTo(1.0, 10);
  });
});
